// Noncompliant: Too many return statements (4 returns)
int processValue(int x) {
  if (x < 0) {
    return -1;  // 1st return
  }
  if (x == 0) {
    return 0;   // 2nd return
  }
  if (x > 100) {
    return 100; // 3rd return
  }
  return x;     // 4th return
}

compliant:
// Compliant: Single return statement
int processValue(int x) {
  int result;
  if (x < 0) {
    result = -1;
  } else if (x == 0) {
    result = 0;
  } else if (x > 100) {
    result = 100;
  } else {
    result = x;
  }
  return result;
}
